/* BIM AI design tokens — default (light) chrome.
 *
 * Source of truth: spec/ui-ux-redesign-v1-spec.md §9 (chrome subset).
 * Drafting / category / line-weight tokens live in tokens-drafting.css.
 * Dark overrides live in tokens-dark.css.
 *
 * Naming rule: every token is semantic (no color literals in token names).
 */

:root,
:root[data-theme='light'] {
  /* §9.1 Color — semantic chrome */
  --color-background: hsl(0 0% 100%);
  --color-foreground: hsl(220 18% 14%);
  --color-surface: hsl(220 16% 98%);
  --color-surface-strong: hsl(220 16% 95%);
  --color-surface-muted: hsl(220 16% 96%);
  --color-border: hsl(220 13% 90%);
  --color-border-strong: hsl(220 13% 80%);
  --color-muted-foreground: hsl(220 10% 44%);
  --color-accent: hsl(214 88% 50%);
  --color-accent-foreground: hsl(0 0% 100%);
  --color-accent-soft: color-mix(in srgb, hsl(214 88% 50%) 12%, hsl(0 0% 100%));
  --color-success: hsl(150 56% 38%);
  --color-warning: hsl(38 92% 50%);
  --color-danger: hsl(0 72% 50%);
  --color-info: hsl(213 86% 56%);
  --color-ring: color-mix(in srgb, hsl(214 88% 50%) 38%, transparent);

  /* §9.4 Spacing (4 px base) */
  --space-0: 0;
  --space-1: 2px;
  --space-2: 4px;
  --space-3: 6px;
  --space-4: 8px;
  --space-5: 12px;
  --space-6: 16px;
  --space-7: 20px;
  --space-8: 24px;
  --space-10: 32px;
  --space-12: 40px;

  /* §9.5 Radius */
  --radius-xs: 3px;
  --radius-sm: 4px;
  --radius-md: 6px;
  --radius-lg: 10px;
  --radius-xl: 14px;
  --radius-pill: 999px;

  /* §9.6 Typography */
  --font-sans:
    'Inter', ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto,
    Helvetica, Arial, 'Apple Color Emoji', 'Segoe UI Emoji';
  --font-mono:
    'JetBrains Mono', ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono',
    'Courier New', monospace;

  --text-xs: 11px;
  --text-xs-line: 16px;
  --text-sm: 12.5px;
  --text-sm-line: 18px;
  --text-base: 14px;
  --text-base-line: 20px;
  --text-md: 15px;
  --text-md-line: 22px;
  --text-lg: 17px;
  --text-lg-line: 24px;
  --text-xl: 20px;
  --text-xl-line: 28px;
  --text-mono-xs: 11px;
  --text-mono-xs-line: 16px;
  --text-mono-sm: 12px;
  --text-mono-sm-line: 18px;
  --text-eyebrow-tracking: 0.04em;

  /* §9.7 Elevation */
  --elev-0: none;
  --elev-1: 0 1px 2px hsl(220 18% 14% / 0.04), 0 1px 1px hsl(220 18% 14% / 0.04);
  --elev-2: 0 4px 8px hsl(220 18% 14% / 0.06), 0 2px 4px hsl(220 18% 14% / 0.04);
  --elev-3: 0 12px 24px hsl(220 18% 14% / 0.08), 0 4px 8px hsl(220 18% 14% / 0.06);

  /* §9.8 Motion */
  --motion-fast: 80ms;
  --motion-base: 140ms;
  --motion-slow: 240ms;
  --ease-out: cubic-bezier(0.2, 0.8, 0.2, 1);
  --ease-in-out: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-snap: cubic-bezier(0.7, 0, 0.3, 1);

  /* §8 Shell sizing */
  --shell-topbar-height: 48px;
  --shell-statusbar-height: 28px;
  --shell-rail-left-width: 256px;
  --shell-rail-right-width: 320px;
  --shell-rail-left-collapsed-width: 56px;
  --shell-bp-md: 1280px;
  --shell-bp-lg: 1600px;

  /* Backwards-compatible legacy aliases (pre-v1 components still read these). */
  --background: var(--color-background);
  --foreground: var(--color-foreground);
  --surface: var(--color-surface);
  --border: var(--color-border);
  --muted-foreground: var(--color-muted-foreground);
  --accent: var(--color-accent);
  --accent-foreground: var(--color-accent-foreground);
  --ring: var(--color-ring);
}

@media (prefers-reduced-motion: reduce) {
  :root,
  :root[data-theme='light'],
  :root[data-theme='dark'],
  :root.dark {
    --motion-fast: 0ms;
    --motion-base: 0ms;
    --motion-slow: 0ms;
  }
}

