10	} from 'react';
11	import { useTranslation } from 'react-i18next';
12	import { Icons, IconLabels, ICON_SIZE, type LucideLikeIcon } from '@bim-ai/ui';
13	
14	/**
15	 * TopBar — spec §11.
16	 *
17	 * Three regions:
18	 *   1. Left  (240 px): hamburger toggle, logo placeholder, project-name button.
19	 *   2. Center: mode pills traversable with arrow keys (`role="tablist"`).
20	 *   3. Right: command palette button, collaborators count, settings, theme
21	 *      toggle, avatar.
22	 *
23	 * The TopBar is purely presentational. State (current mode, theme,
24	 * collaborators) is owned by callers (Workspace + Mode-switching WP-D03).
25	 */
26	
27	export const WORKSPACE_MODES = [
28	  { id: 'plan', label: 'Plan', hotkey: '1' },
29	  { id: '3d', label: '3D', hotkey: '2' },
30	  { id: 'plan-3d', label: 'Plan + 3D', hotkey: '3' },
31	  { id: 'section', label: 'Section', hotkey: '4' },
32	  { id: 'sheet', label: 'Sheet', hotkey: '5' },
33	  { id: 'schedule', label: 'Schedule', hotkey: '6' },
34	  { id: 'agent', label: 'Agent', hotkey: '7' },
35	] as const;
36	
37	export type WorkspaceMode = (typeof WORKSPACE_MODES)[number]['id'];
38	
39	export interface TopBarSelectOption {
40	  id: string;
41	  label: string;
42	}
43	
44	export interface TopBarProps {
45	  mode: WorkspaceMode;
46	  onModeChange: (next: WorkspaceMode) => void;
47	  projectName: string;
48	  onProjectNameClick?: () => void;
49	  /** Forwarded to the project-name pill so external popovers can anchor. */
50	  projectNameRef?: React.RefObject<HTMLButtonElement | null>;
51	  onHamburgerClick?: () => void;
52	  theme: 'light' | 'dark';
53	  onThemeToggle?: () => void;
54	  onCommandPalette?: () => void;
55	  onSettings?: () => void;
56	  collaboratorsCount?: number;
57	  onCollaboratorsClick?: () => void;
58	  /** Identifier shown as the avatar fallback when no avatar URL is provided. */
59	  avatarInitials?: string;
60	  /** Presence peers to render as avatar chips (up to 6). */
61	  peers?: Array<{ name?: string; color?: string }>;
62	  /** Discipline/perspective filter selector. */
63	  perspectiveOptions?: TopBarSelectOption[];
64	  perspectiveValue?: string;
65	  onPerspectiveChange?: (id: string) => void;
66	  /** Plan presentation style selector. */
67	  planStyleOptions?: TopBarSelectOption[];
68	  planStyleValue?: string;
69	  onPlanStyleChange?: (id: string) => void;
70	}
71	
72	export function TopBar({
73	  mode,
74	  onModeChange,
75	  projectName,
76	  onProjectNameClick,
77	  projectNameRef,
78	  onHamburgerClick,
79	  theme,
80	  onThemeToggle,
81	  onCommandPalette,
82	  onSettings,
83	  collaboratorsCount,
84	  onCollaboratorsClick,
85	  avatarInitials,
86	  peers,
87	  perspectiveOptions,
88	  perspectiveValue,
89	  onPerspectiveChange,
90	  planStyleOptions,
91	  planStyleValue,
92	  onPlanStyleChange,
93	}: TopBarProps): JSX.Element {
94	  const tablistId = useId();
95	  return (
96	    <div
97	      data-testid="topbar"
98	      role="banner"
99	      style={topBarStyle}
100	      className="flex w-full items-center gap-4 border-b border-border bg-background px-4"
101	    >
102	      <TopBarLeft
103	        projectName={projectName}
104	        onProjectNameClick={onProjectNameClick}
105	        projectNameRef={projectNameRef}
106	        onHamburgerClick={onHamburgerClick}
107	      />
108	      <TopBarModePills tablistId={tablistId} mode={mode} onModeChange={onModeChange} />
109	      <TopBarRight
110	        theme={theme}
111	        onThemeToggle={onThemeToggle}
112	        onCommandPalette={onCommandPalette}
113	        onSettings={onSettings}
114	        collaboratorsCount={collaboratorsCount}
115	        onCollaboratorsClick={onCollaboratorsClick}
116	        avatarInitials={avatarInitials}
117	        peers={peers}
118	        perspectiveOptions={perspectiveOptions}
119	        perspectiveValue={perspectiveValue}
120	        onPerspectiveChange={onPerspectiveChange}
