import { type CSSProperties, type JSX, useEffect, useMemo } from 'react';
import { Icons, ICON_SIZE } from '@bim-ai/ui';
import { WorkspaceSwitcher } from './WorkspaceSwitcher';
import type { WorkspaceId } from './workspaces';

export interface TopBarV3Props {
  // Slot 2
  projectName: string;
  currentProjectId: string;
  onProjectNameClick?: () => void;
  projectNameRef?: React.RefObject<HTMLButtonElement | null>;
  // Slot 3 — workspace switcher (CHR-V3-02)
  activeWorkspaceId: WorkspaceId;
  userPreferredWorkspace: WorkspaceId;
  onWorkspaceSwitcherSelect?: (id: WorkspaceId) => void;
  // Slot 5
  onCommandPalette?: () => void;
  // Slot 6
  onActivityStream?: () => void;
  // Slot 7 — presence
  presence?: Array<{ userId: string; name?: string; color?: string }>;
  // Slot 8
  theme: 'light' | 'dark';
  onThemeToggle?: () => void;
  onSettings?: () => void;
  avatarInitials?: string;
  onHamburgerClick?: () => void;
}

const topBarStyle: CSSProperties = {
  height: 'var(--shell-topbar-height)',
  minHeight: 'var(--shell-topbar-height)',
  backgroundColor: 'var(--color-surface)',
  borderBottom: '1px solid var(--color-border)',
  borderRadius: 'var(--radius-canvas)',
};

export function TopBarV3({
  projectName,
  onProjectNameClick,
  projectNameRef,
  activeWorkspaceId,
  userPreferredWorkspace,
  onWorkspaceSwitcherSelect,
  onCommandPalette,
  onActivityStream,
  presence,
  theme,
  onThemeToggle,
  onSettings,
  avatarInitials,
  onHamburgerClick,
}: TopBarV3Props): JSX.Element {
  const cmdKLabel = useMemo(() => {
    if (typeof navigator !== 'undefined' && navigator.platform.toLowerCase().includes('mac')) {
      return '⌘K';
    }
    return 'Ctrl+K';
  }, []);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'h') {
        e.preventDefault();
        onActivityStream?.();
      }
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [onActivityStream]);

  const visiblePeers = (presence ?? []).slice(0, 4);
  const overflowCount = (presence ?? []).length - visiblePeers.length;
  const hasPresence = (presence ?? []).length > 0;

  return (
    <div
      data-testid="topbar-v3"
      role="banner"
      style={topBarStyle}
      className="flex w-full items-center gap-2 px-2"
    >
      {/* Hamburger */}
      <button
        type="button"
        onClick={onHamburgerClick}
        aria-label="Toggle navigation"
        title="Toggle navigation"
        style={{
          width: 32,
          height: 32,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: 'var(--radius-md)',
          color: 'var(--color-muted-foreground)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
          flexShrink: 0,
        }}
      >
        <Icons.hamburger size={ICON_SIZE.chrome} aria-hidden="true" />
      </button>

      {/* Slot 1 — Logo mark */}
      <div
        aria-label="bim-ai home"
        style={{
          width: 40,
          height: 40,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexShrink: 0,
          color: 'var(--brand-accent)',
          fontWeight: 700,
          fontSize: 'var(--text-sm)',
        }}
      >
        BA
      </div>

      {/* Slot 2 — Project name */}
      <button
        type="button"
        ref={projectNameRef}
        onClick={onProjectNameClick}
        aria-haspopup="menu"
        data-testid="topbar-v3-project-name"
        title={projectName}
        style={{
          fontSize: 'var(--text-base)',
          lineHeight: 'var(--text-base-line)',
          fontWeight: 600,
          borderRadius: 'var(--radius-md)',
          padding: '2px 8px',
          color: 'var(--color-foreground)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
          display: 'flex',
          alignItems: 'center',
          gap: 4,
        }}
      >
        <span
          style={{ maxWidth: 180, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
        >
          {projectName}
        </span>
        <Icons.disclosureOpen size={12} aria-hidden="true" />
      </button>

      {/* Slot 3 — Workspace switcher */}
      <WorkspaceSwitcher
        activeWorkspaceId={activeWorkspaceId}
        userPreferredWorkspace={userPreferredWorkspace}
        onSetActiveWorkspace={onWorkspaceSwitcherSelect ?? (() => undefined)}
      />

      {/* Slot 4 — Flex stretch */}
      <div style={{ flex: 1 }} aria-hidden="true" />

      {/* Slot 5 — Cmd+K */}
      <button
        type="button"
        onClick={onCommandPalette}
        aria-label="Command palette"
        aria-keyshortcuts="Meta+K Control+K"
        data-testid="topbar-v3-cmdpalette"
        title={`Command palette  ${cmdKLabel}`}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 6,
          padding: '4px 8px',
          borderRadius: 'var(--radius-md)',
          border: '1px solid var(--color-border)',
          backgroundColor: 'var(--color-surface)',
          color: 'var(--color-muted-foreground)',
          fontSize: 'var(--text-sm)',
          lineHeight: 'var(--text-sm-line)',
          cursor: 'pointer',
        }}
      >
        <Icons.commandPalette size={ICON_SIZE.chrome} aria-hidden="true" />
        <span style={{ fontVariantNumeric: 'tabular-nums' }}>{cmdKLabel}</span>
      </button>

      {/* Slot 6 — Activity stream */}
      <button
        type="button"
        onClick={onActivityStream}
        aria-label="Activity stream"
        aria-keyshortcuts="Meta+H"
        data-testid="topbar-v3-activity"
        title="Activity stream  ⌘H"
        style={{
          width: 32,
          height: 32,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: 'var(--radius-md)',
          color: 'var(--color-muted-foreground)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
        }}
      >
        <Icons.online size={ICON_SIZE.chrome} aria-hidden="true" />
      </button>

      {/* Slot 7 — Presence avatars */}
      {hasPresence && (
        <div
          data-testid="topbar-v3-presence"
          className="flex items-center"
          aria-label="Active collaborators"
          style={{ marginLeft: 2, marginRight: 2 }}
        >
          {visiblePeers.map((p, i) => (
            <div
              key={p.userId}
              title={p.name ?? 'Anonymous'}
              style={{
                width: 24,
                height: 24,
                borderRadius: 'var(--radius-pill)',
                border: '2px solid var(--color-surface)',
                backgroundColor: p.color ?? 'var(--color-surface-strong)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 9,
                fontWeight: 600,
                color: 'var(--color-foreground)',
                marginLeft: i > 0 ? -6 : 0,
                zIndex: 4 - i,
                position: 'relative',
              }}
            >
              {(p.name ?? '?').slice(0, 2).toUpperCase()}
            </div>
          ))}
          {overflowCount > 0 && (
            <div
              style={{
                width: 24,
                height: 24,
                borderRadius: 'var(--radius-pill)',
                border: '2px solid var(--color-surface)',
                backgroundColor: 'var(--brand-accent)',
                color: 'var(--brand-accent-fg)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 9,
                fontWeight: 600,
                marginLeft: -6,
                position: 'relative',
                zIndex: 0,
              }}
            >
              +{overflowCount}
            </div>
          )}
        </div>
      )}

      {/* Slot 8 — Profile / settings */}
      <button
        type="button"
        onClick={onThemeToggle}
        aria-label={theme === 'dark' ? 'Light theme' : 'Dark theme'}
        title={theme === 'dark' ? 'Light theme' : 'Dark theme'}
        data-testid="topbar-v3-theme-toggle"
        data-current-theme={theme}
        style={{
          width: 32,
          height: 32,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: 'var(--radius-md)',
          color: 'var(--color-muted-foreground)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
        }}
      >
        {theme === 'dark' ? (
          <Icons.themeLight size={ICON_SIZE.chrome} aria-hidden="true" />
        ) : (
          <Icons.themeDark size={ICON_SIZE.chrome} aria-hidden="true" />
        )}
      </button>
      <button
        type="button"
        onClick={onSettings}
        aria-label="Settings"
        title="Settings"
        style={{
          width: 32,
          height: 32,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: 'var(--radius-md)',
          color: 'var(--color-muted-foreground)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
        }}
      >
        <Icons.settings size={ICON_SIZE.chrome} aria-hidden="true" />
      </button>
      <div
        data-testid="topbar-v3-account"
        aria-label="Account"
        title={avatarInitials ?? ''}
        style={{
          width: 28,
          height: 28,
          borderRadius: 'var(--radius-pill)',
          border: '1px solid var(--color-border)',
          backgroundColor: 'color-mix(in srgb, var(--brand-accent) 15%, transparent)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          fontSize: 11,
          fontWeight: 600,
          color: 'var(--brand-accent)',
        }}
      >
        {(avatarInitials ?? '··').slice(0, 2).toUpperCase()}
      </div>
    </div>
  );
}

